```typescript
type ConversationCommand =
  | { type: 'StartConversation'; id: string; starterId: string }
  | { type: 'AddParticipant'; userId: string }
  | { type: 'CloseConversation' };

type ConversationEvent =
  | { type: 'ConversationStarted'; id: string; starterId: string }
  | { type: 'ParticipantAdded'; userId: string }
  | { type: 'ConversationClosed' };

type ConversationState =
  | { status: 'empty' }
  | { status: 'open'; id: string; participants: readonly string[] }
  | { status: 'closed'; id: string; participants: readonly string[] };

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

class InvariantError extends Error {}

export const ConversationDecider: Decider<ConversationCommand, ConversationEvent, ConversationState> = {
  initialState: { status: 'empty' },
  decide(command, state) {
    switch (command.type) {
      case 'StartConversation':
        if (state.status !== 'empty') throw new InvariantError('already started');
        return [{ type: 'ConversationStarted', id: command.id, starterId: command.starterId }];
      case 'AddParticipant':
        if (state.status !== 'open') throw new InvariantError('not open');
        return [{ type: 'ParticipantAdded', userId: command.userId }];
      case 'CloseConversation':
        if (state.status !== 'open') throw new InvariantError('cannot close');
        return [{ type: 'ConversationClosed' }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'ConversationStarted':
        return { status: 'open', id: event.id, participants: [event.starterId] };
      case 'ParticipantAdded':
        if (state.status !== 'open') return state;
        return { ...state, participants: [...state.participants, event.userId] };
      case 'ConversationClosed':
        if (state.status !== 'open') return state;
        return { status: 'closed', id: state.id, participants: state.participants };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
