type ThreadCommand =
  | { type: 'OpenThread'; id: string; topic: string }
  | { type: 'PinThread' }
  | { type: 'ArchiveThread' };

type ThreadEvent =
  | { type: 'ThreadOpened'; id: string; topic: string }
  | { type: 'ThreadPinned' }
  | { type: 'ThreadArchived' };

type ThreadState =
  | { status: 'none' }
  | { status: 'open'; id: string; pinned: boolean; topic: string }
  | { status: 'archived'; id: string };

class ThreadRuleError extends Error {}

export function decide(command: ThreadCommand, state: ThreadState): ThreadEvent[] {
  switch (command.type) {
    case 'OpenThread':
      if (state.status !== 'none') throw new ThreadRuleError('already opened');
      return [{ type: 'ThreadOpened', id: command.id, topic: command.topic }];
    case 'PinThread':
      if (state.status !== 'open') throw new ThreadRuleError('cannot pin');
      if (state.pinned) return [];
      return [{ type: 'ThreadPinned' }];
    case 'ArchiveThread':
      if (state.status !== 'open') throw new ThreadRuleError('cannot archive');
      return [{ type: 'ThreadArchived' }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ThreadState, event: ThreadEvent): ThreadState {
  switch (event.type) {
    case 'ThreadOpened':
      return { status: 'open', id: event.id, pinned: false, topic: event.topic };
    case 'ThreadPinned':
      return state.status === 'open' ? { ...state, pinned: true } : state;
    case 'ThreadArchived':
      return state.status === 'open' ? { status: 'archived', id: state.id } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const initialState: ThreadState = { status: 'none' };
