Reactions are small but require a rule: only one active emoji per user per post. The decider tracks presence/absence and lets a change emit a single `ReactionChanged` event.

```typescript
type ReactionCommand =
  | { type: 'AddReaction'; userId: string; postId: string; emoji: string }
  | { type: 'ChangeReaction'; emoji: string }
  | { type: 'RemoveReaction' };

type ReactionEvent =
  | { type: 'ReactionAdded'; userId: string; postId: string; emoji: string }
  | { type: 'ReactionChanged'; emoji: string }
  | { type: 'ReactionRemoved' };

type ReactionState =
  | { status: 'none' }
  | { status: 'active'; userId: string; postId: string; emoji: string };

class ReactionRuleError extends Error {}

export function decide(command: ReactionCommand, state: ReactionState): ReactionEvent[] {
  switch (command.type) {
    case 'AddReaction':
      if (state.status === 'active') throw new ReactionRuleError('already reacted');
      return [{ type: 'ReactionAdded', userId: command.userId, postId: command.postId, emoji: command.emoji }];
    case 'ChangeReaction':
      if (state.status !== 'active') throw new ReactionRuleError('no reaction');
      if (state.emoji === command.emoji) return [];
      return [{ type: 'ReactionChanged', emoji: command.emoji }];
    case 'RemoveReaction':
      if (state.status !== 'active') return [];
      return [{ type: 'ReactionRemoved' }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ReactionState, event: ReactionEvent): ReactionState {
  switch (event.type) {
    case 'ReactionAdded':
      return { status: 'active', userId: event.userId, postId: event.postId, emoji: event.emoji };
    case 'ReactionChanged':
      return state.status === 'active' ? { ...state, emoji: event.emoji } : state;
    case 'ReactionRemoved':
      return { status: 'none' };
    default: {
      const _: never = event;
      return _;
    }
  }
}
