type ReplyCommand =
  | { type: 'PostReply'; id: string; parentId: string; authorId: string; body: string }
  | { type: 'MarkReplyHelpful'; by: string }
  | { type: 'RetractReply'; at: string };

type ReplyEvent =
  | { type: 'ReplyPosted'; id: string; parentId: string; authorId: string; body: string }
  | { type: 'ReplyMarkedHelpful'; by: string }
  | { type: 'ReplyRetracted'; at: string };

type ReplyState =
  | { status: 'absent' }
  | { status: 'live'; id: string; helpfulBy: readonly string[] }
  | { status: 'retracted' };

class ReplyRuleError extends Error {}

export function decide(command: ReplyCommand, state: ReplyState): ReplyEvent[] {
  switch (command.type) {
    case 'PostReply':
      if (state.status !== 'absent') throw new ReplyRuleError('already posted');
      return [{ type: 'ReplyPosted', id: command.id, parentId: command.parentId, authorId: command.authorId, body: command.body }];
    case 'MarkReplyHelpful':
      if (state.status !== 'live') throw new ReplyRuleError('not live');
      if (state.helpfulBy.includes(command.by)) return [];
      return [{ type: 'ReplyMarkedHelpful', by: command.by }];
    case 'RetractReply':
      if (state.status !== 'live') throw new ReplyRuleError('not live');
      return [{ type: 'ReplyRetracted', at: command.at }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ReplyState, event: ReplyEvent): ReplyState {
  switch (event.type) {
    case 'ReplyPosted':
      return { status: 'live', id: event.id, helpfulBy: [] };
    case 'ReplyMarkedHelpful':
      return state.status === 'live' ? { ...state, helpfulBy: [...state.helpfulBy, event.by] } : state;
    case 'ReplyRetracted':
      return state.status === 'live' ? { status: 'retracted' } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}
