A projection should handle only events it cares about and return the view unchanged for others. Here a `ThreadSummary` tracks reply count and last poster; non-thread events are ignored.

```typescript
type DomainEvent =
  | { type: 'ThreadOpened'; threadId: string; topic: string }
  | { type: 'ReplyPosted'; threadId: string; authorId: string; at: string }
  | { type: 'ThreadArchived'; threadId: string }
  | { type: 'UnrelatedDomainEvent'; payload: string };

type ThreadSummary = Readonly<{
  threadId: string;
  topic: string;
  replyCount: number;
  lastPosterId: string | null;
  archived: boolean;
}>;

export const emptySummary: ThreadSummary = {
  threadId: '',
  topic: '',
  replyCount: 0,
  lastPosterId: null,
  archived: false,
};

export function project(view: ThreadSummary, event: DomainEvent): ThreadSummary {
  switch (event.type) {
    case 'ThreadOpened':
      return { ...view, threadId: event.threadId, topic: event.topic };
    case 'ReplyPosted':
      return { ...view, replyCount: view.replyCount + 1, lastPosterId: event.authorId };
    case 'ThreadArchived':
      return { ...view, archived: true };
    case 'UnrelatedDomainEvent':
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function rebuildSummary(events: DomainEvent[]): ThreadSummary {
  return events.reduce(project, emptySummary);
}
