type ConversationV1 = Readonly<{ id: string; users: readonly string[] }>;
type ConversationV2 = Readonly<{ id: string; members: readonly string[] }>;
type ConversationV3 = Readonly<{ id: string; members: readonly string[]; closed: boolean }>;

export type CurrentConversation = ConversationV3;

export type Snapshot<S> = Readonly<{ version: number; state: S }>;

export const CURRENT_VERSION = 3 as const;

function v1Tov2(s: ConversationV1): ConversationV2 {
  return { id: s.id, members: s.users };
}

function v2Tov3(s: ConversationV2): ConversationV3 {
  return { id: s.id, members: s.members, closed: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentConversation> {
  let { version, state } = snap;
  if (version === 1) {
    state = v1Tov2(state as ConversationV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ConversationV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unknown snapshot version: ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentConversation };
}
