    state = v1Tov2(state as ThreadV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ThreadV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unsupported snapshot version: ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentThread };
