type RawEvent =
  | { type: 'MessagePosted'; version: 1; data: { id: string; text: string } }
  | { type: 'MessagePosted'; version: 2; data: { id: string; body: string } }
  | { type: 'MessageEdited'; version: 1; data: { body: string } };

type CurrentEvent =
  | { type: 'MessagePosted'; id: string; body: string }
  | { type: 'MessageEdited'; body: string };

export class UnknownEventError extends Error {
  constructor(public readonly rawType: string, public readonly version: number) {
    super(`unknown event ${rawType}@${version}`);
  }
}

export function upcast(raw: RawEvent): CurrentEvent {
  if (raw.type === 'MessagePosted' && raw.version === 1) {
    return { type: 'MessagePosted', id: raw.data.id, body: raw.data.text };
  }
  if (raw.type === 'MessagePosted' && raw.version === 2) {
    return { type: 'MessagePosted', id: raw.data.id, body: raw.data.body };
  }
  if (raw.type === 'MessageEdited' && raw.version === 1) {
    return { type: 'MessageEdited', body: raw.data.body };
  }
  const exhaustive: RawEvent = raw;
  throw new UnknownEventError(exhaustive.type, exhaustive.version);
}

interface EventStore {
  readStream(stream: string): AsyncIterable<RawEvent>;
}

export async function readAndUpcast(store: EventStore, stream: string): Promise<CurrentEvent[]> {
  const out: CurrentEvent[] = [];
  for await (const raw of store.readStream(stream)) {
    out.push(upcast(raw));
  }
  return out;
}
```

Upcasting transforms an old stored event shape into the current one at read time, so you never have to rewrite the stream. The reader pattern-matches on `{ type, version }` and returns the current event. An unknown tuple throws, forcing explicit handling of every shape that ever existed.

