  while (cursor !== null) {
    const { events, nextFrom } = await opts.events.read(cursor, opts.batchSize);
    const map = new Map<string, ParticipantsView>();
    for (const { event } of events) {
      const existing =
        map.get(event.conversationId) ??
        (await opts.store.loadView(event.conversationId)) ??
