type ThreadCommand =
  | { type: 'OpenThread'; id: string; topic: string }
  | { type: 'ArchiveThread'; id: string };

type ThreadEvent =
  | { type: 'ThreadOpened'; id: string; topic: string }
  | { type: 'ThreadArchived'; id: string };

type WriteState = { status: 'none' } | { status: 'open'; id: string } | { status: 'archived'; id: string };

const initialWrite: WriteState = { status: 'none' };

function evolve(state: WriteState, event: ThreadEvent): WriteState {
  switch (event.type) {
    case 'ThreadOpened':
      return { status: 'open', id: event.id };
    case 'ThreadArchived':
      return state.status === 'open' ? { status: 'archived', id: state.id } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: ThreadCommand, state: WriteState): ThreadEvent[] {
  switch (command.type) {
    case 'OpenThread':
      if (state.status !== 'none') throw new Error('exists');
      return [{ type: 'ThreadOpened', id: command.id, topic: command.topic }];
    case 'ArchiveThread':
      if (state.status !== 'open') throw new Error('cannot archive');
      return [{ type: 'ThreadArchived', id: command.id }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

interface EventStore {
  readStream(s: string): AsyncIterable<ThreadEvent>;
  appendToStream(s: string, events: readonly ThreadEvent[]): Promise<void>;
}

export interface ThreadListItem {
  id: string;
  topic: string;
  archived: boolean;
}
interface ReadStore {
  get(id: string): Promise<ThreadListItem | null>;
}

export async function handleCommand(store: EventStore, streamName: string, command: ThreadCommand): Promise<void> {
  let state = initialWrite;
  for await (const event of store.readStream(streamName)) {
    state = evolve(state, event);
  }
  await store.appendToStream(streamName, decide(command, state));
}

export async function queryView(read: ReadStore, id: string): Promise<ThreadListItem | null> {
  return read.get(id);
}
