  stream: string,
  events: readonly ChannelEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: bigint | 'no_stream',
): Promise<void> {
  // Single unit of work: outbox rows + stream append commit together.
  await conn.inTransaction(async (tx) => {
    await tx.insertOutbox(outboxRows);
    await tx.appendToStream(stream, events, { expectedRevision });
  });
  // A separate publisher worker polls `outbox WHERE published_at IS NULL`,
  // pushes each row to the message bus, and sets published_at on success.
}
