The offending code couples a domain state machine to XState. Event-sourcing wants the state transitions to live in a pure `evolve` reducer and the guards in a pure `decide`. Replace the machine with a Decider record.

```typescript
type MessageCommand =
  | { type: 'PostMessage'; id: string; body: string }
  | { type: 'EditMessage'; body: string };

type MessageEvent =
  | { type: 'MessagePosted'; id: string; body: string }
  | { type: 'MessageEdited'; body: string };

type MessageState =
  | { status: 'draft' }
  | { status: 'live'; id: string; body: string };

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const MessageDecider: Decider<MessageCommand, MessageEvent, MessageState> = {
  initialState: { status: 'draft' },
  decide(command, state) {
    switch (command.type) {
      case 'PostMessage':
        if (state.status !== 'draft') throw new Error('already posted');
        return [{ type: 'MessagePosted', id: command.id, body: command.body }];
      case 'EditMessage':
        if (state.status !== 'live') throw new Error('not live');
        return [{ type: 'MessageEdited', body: command.body }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'MessagePosted':
        return { status: 'live', id: event.id, body: event.body };
      case 'MessageEdited':
        return state.status === 'live' ? { ...state, body: event.body } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
