type BroadcastGroupCommand =
  | { type: 'CreateBroadcastGroup'; id: string; name: string }
  | { type: 'AddRecipient'; userId: string }
  | { type: 'SendBroadcast'; body: string; at: string };

type BroadcastGroupEvent =
  | { type: 'BroadcastGroupCreated'; id: string; name: string }
  | { type: 'RecipientAdded'; userId: string }
  | { type: 'BroadcastSent'; body: string; at: string };

type BroadcastGroupState =
  | { status: 'empty' }
  | { status: 'ready'; id: string; name: string; recipients: readonly string[] };

class BroadcastRuleError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const BroadcastGroupDecider: Decider<BroadcastGroupCommand, BroadcastGroupEvent, BroadcastGroupState> = {
  initialState: { status: 'empty' },
  decide(command, state) {
    switch (command.type) {
      case 'CreateBroadcastGroup':
        if (state.status !== 'empty') throw new BroadcastRuleError('exists');
        return [{ type: 'BroadcastGroupCreated', id: command.id, name: command.name }];
      case 'AddRecipient':
        if (state.status !== 'ready') throw new BroadcastRuleError('not ready');
        if (state.recipients.includes(command.userId)) return [];
        return [{ type: 'RecipientAdded', userId: command.userId }];
      case 'SendBroadcast':
        if (state.status !== 'ready') throw new BroadcastRuleError('not ready');
        if (state.recipients.length === 0) throw new BroadcastRuleError('no recipients');
        return [{ type: 'BroadcastSent', body: command.body, at: command.at }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case 'BroadcastGroupCreated':
        return { status: 'ready', id: event.id, name: event.name, recipients: [] };
      case 'RecipientAdded':
        return state.status === 'ready'
          ? { ...state, recipients: [...state.recipients, event.userId] }
          : state;
      case 'BroadcastSent':
        return state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
